codeExample:
Get-Service |
    Where-Object { $_.Status -eq 'Running' } |
    ForEach-Object { "Service: $($PSItem.Name)" }

Get-Item .\missing.txt -ErrorAction SilentlyContinue
if (-not $?) { Write-Warning 'Previous command failed' }

$params = @{
    Path        = 'C:\logs'
    Filter      = '*.log'
    Recurse     = $true
    ErrorAction = 'Stop'
}

Get-ChildItem @params

# Conditionally add a parameter
if ($verbose) { $params['Verbose'] = $true }

try {
    Get-Content .\config.json -ErrorAction Stop
}
catch [System.IO.FileNotFoundException] {
    Write-Warning "Missing file: $($_.Exception.Message)"
}
catch {
    Write-Error "Unexpected: $($_.Exception.Message)"
}
finally {
    Write-Verbose 'Cleanup complete'
}

$ErrorActionPreference = 'Stop'

try {
    Remove-Item .\locked.txt   # now terminating
}
catch {
    Write-Host "Handled: $($_.Exception.Message)"
}

# Per-command override
Get-Item .\maybe.txt -ErrorAction SilentlyContinue

function Convert-ToUpper {
    [CmdletBinding()]
    param(
        [Parameter(ValueFromPipeline)]
        [string]$Text
    )
    process {
        $Text.ToUpper()
    }
}

'alpha', 'beta' | Convert-ToUpper   # ALPHA, BETA

$servers = 'web01', 'web02', 'web03'

Invoke-Command -ComputerName $servers -ScriptBlock {
    Get-Service -Name W3SVC |
        Select-Object Name, Status
} -ThrottleLimit 10

# Reuse a persistent session
$s = New-PSSession -ComputerName web01
Invoke-Command -Session $s -ScriptBlock { $env:COMPUTERNAME }
